query:
query CrmIndexSearchQuery($filterGroups: [FilterGroup!]!, $sorts: [Sort!], $query: String, $objectTypeId: String!, $properties: [String!]!, $count: Int, $offset: Int) {
  crmObjectsSearch(
    filterGroups: $filterGroups
    sorts: $sorts
    query: $query
    type: $objectTypeId
    count: $count
    offset: $offset
  ) {
    total
    offset
    results {
      ...CrmIndexObjectFragment
      __typename
    }
    validationErrors {
      __typename
      ... on GenericValidationError {
        message
        __typename
      }
    }
    __typename
  }
}

fragment CrmIndexObjectFragment on CrmObject {
  id
  objectId: id
  properties(names: $properties) {
    id
    name
    value
    __typename
  }
  userPermissions {
    currentUserCanEdit
    currentUserCanDelete
    __typename
  }
  __typename
}
